INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 103311, "", 870, "", "", 13, 1033501, "", 1033501039);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 103311, 1, "急に牛乳と卵が欲しいっつうから\n何かと思ったけんど、まさか\nオラのためにこんな立派なケーキ\n用意してくれてただなんてな！", 0, 0, 11, 1033501, "", 1033501040);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1033501, "", 1033501041);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1033501", 0, "vo_adv_1033501_001", "", "", 21, 1033501, "", 1033501042);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 5, 103311, 1, "オラの食材とあんちゃんの腕……\nこれは二人の共同作業ってことに……\nな、なんでもねぇ！\n気にしねぇでけろ！", 0, 0, 11, 1033501, "", 1033501043);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1033501, "", 1033501044);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1033501", 0, "vo_adv_1033501_002", "", "", 21, 1033501, "", 1033501045);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 103311, 1, "それにしても食べるのが\nもったいねぇいいケーキだなぁ……\nでも食べなきゃ食べねぇで\nもったいねぇよなぁ……", 0, 0, 11, 1033501, "", 1033501046);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1033501, "", 1033501047);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1033501", 0, "vo_adv_1033501_003", "", "", 21, 1033501, "", 1033501048);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 103311, 1, "うーん……\nオラ一人で食べるのも申し訳ねぇし\nエリザベスパークのみんなで\n食べるべか！", 0, 0, 11, 1033501, "", 1033501049);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1033501, "", 1033501050);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1033501", 0, "vo_adv_1033501_004", "", "", 21, 1033501, "", 1033501051);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 103311, 1, "みんなで過ごすのがオラにとって\n最高の誕生日だべ！\nあんがとな、あんちゃん！", 0, 0, 11, 1033501, "", 1033501052);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1033501, "", 1033501053);
