INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 4, 103411, 1, "わあ……素敵なケーキね！\nえ？　キミが作ったの？\nすごいじゃない！", 0, 0, 11, 1034501, "", 1034501040);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1034501, "", 1034501041);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1034501", 0, "vo_adv_1034501_001", "", "", 21, 1034501, "", 1034501042);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 103411, 1, "麦しゅわに合わないかも……って、\nそんな気を使わなくていいわよ。\nだって、今日は飲むつもりはないもの。", 0, 0, 11, 1034501, "", 1034501043);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1034501, "", 1034501044);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1034501", 0, "vo_adv_1034501_002", "", "", 21, 1034501, "", 1034501045);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 5, 103411, 1, "なんでって、それは……\nキミがお祝いに来てくれるかも、\nなんて思ってたから……", 0, 0, 11, 1034501, "", 1034501046);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1034501, "", 1034501047);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1034501", 0, "vo_adv_1034501_003", "", "", 21, 1034501, "", 1034501048);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 5, 103411, 1, "だから、今日は麦しゅわは封印よ。\n麦しゅわもありの大人な誕生日は、\nキミが大人になってから……ね？", 0, 0, 11, 1034501, "", 1034501049);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1034501, "", 1034501050);
