INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 104611, 1, "たい焼きの他にケーキまで\n作れるにゃんて……\nキミって意外と料理上手にゃ？", 0, 0, 11, 1046501, "", 1046501043);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1046501, "", 1046501044);
