INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 105111, "", 870, "", "", 13, 1051501, "", 1051501039);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 7, 105111, 1, "誕生日を祝ってくれてありがとう。\nいくつになってもお祝いして\nもらえるのはうれしいものね。", 0, 0, 11, 1051501, "", 1051501040);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1051501, "", 1051501041);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1051501", 0, "vo_adv_1051501_001", "", "", 21, 1051501, "", 1051501042);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 4, 105111, 1, "え、このケーキ君の手作りなの？\nなによ至れり尽くせりじゃない。", 0, 0, 11, 1051501, "", 1051501043);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1051501, "", 1051501044);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1051501", 0, "vo_adv_1051501_002", "", "", 21, 1051501, "", 1051501045);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 105111, 1, "ここまでしてもらったら大人しく\n祝ってもらうしかないわね。\nいくら私でも時と場合は\nちゃんとわきまえるわよ。", 0, 0, 11, 1051501, "", 1051501046);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1051501, "", 1051501047);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1051501", 0, "vo_adv_1051501_003", "", "", 21, 1051501, "", 1051501048);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 105111, 1, "でも、もらってばかりなのは\n性に合わないから、今度お返しに\n体が丈夫になる薬でも\nプレゼントするわ。", 0, 0, 11, 1051501, "", 1051501049);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1051501, "", 1051501050);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1051501", 0, "vo_adv_1051501_004", "", "", 21, 1051501, "", 1051501051);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 105111, 1, "君には健康でいてもらって\nまた誕生日を祝ってもらいたいもの。\nまあ、薬が効きすぎて\n変なことになってもご愛敬ね。", 0, 0, 11, 1051501, "", 1051501052);
