INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1052501", 0, "vo_adv_1052501_000", "", "", 21, 1052501, "", 1052501038);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 105211, "", 870, "", "", 13, 1052501, "", 1052501039);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 105211, 1, "素敵なケーキをありがとう！\nまさかこんな盛大に\nお祝いしてもらえるなんて\n思わなかったわ！", 0, 0, 11, 1052501, "", 1052501040);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1052501, "", 1052501041);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1052501", 0, "vo_adv_1052501_001", "", "", 21, 1052501, "", 1052501042);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 6, 105211, 1, "おめでとうって言ってもらえるだけでも\nうれしいのに、手作りのケーキまで……\n私、あなたにいろんなものを\nもらってばっかりね。", 0, 0, 11, 1052501, "", 1052501043);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1052501, "", 1052501044);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1052501", 0, "vo_adv_1052501_002", "", "", 21, 1052501, "", 1052501045);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 5, 105211, 1, "少しでもお返ししたいけど……\nあなたは何かしてほしいことはある？\nえ？　私の誕生日だから私が\n喜んでくれたらうれしい……？", 0, 0, 11, 1052501, "", 1052501046);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1052501, "", 1052501047);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1052501", 0, "vo_adv_1052501_003", "", "", 21, 1052501, "", 1052501048);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 5, 105211, 1, "私、もう十分に喜んでるわ！\nでも、あなたのそんな言葉を聞いたら\nもう少しわがままを\n言いたくなっちゃうわ。", 0, 0, 11, 1052501, "", 1052501049);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1052501, "", 1052501050);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", 0, "vo_adv_1052501", 0, "vo_adv_1052501_004", "", "", 21, 1052501, "", 1052501051);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES (1, 4, 105211, 1, "ケーキをあーんしてもらってもいい？\n一口だけ、一口だけでいいから！\nいいの？　ありがとう！\n最高の誕生日だわ！", 0, 0, 11, 1052501, "", 1052501052);
INSERT INTO `v1_db8fbf678c16ac3d71b0f1a1184f4b2a6a47cbf5d1496d640458baa6a300f69e` VALUES ("", "", 0, "", "", "", "", 91, 1052501, "", 1052501053);
